SET
  @Name_0ff4f617 = N'ExternalChangeDetection_DetectCreations'
SET
  @CategoryID_0ff4f617 = 'FE1AE5B2-FC57-43B2-B560-A673713E1679'
SET
  @Description_0ff4f617 = N'Detects new records created in an external system by comparing base view rows to existing MJ record changes.'
SET
  @SQL_0ff4f617 = N'-- T-SQL variant for External Change Detection - Detect Creations
SELECT 
    {{ ColumnList }}, ot.[{{ CreatedAtField }}] AS CreatedAt, ot.[{{ UpdatedAtField }}] AS UpdatedAt
FROM 
    [{{ SchemaName }}].[{{ BaseView }}] ot
LEFT JOIN 
    [${flyway:defaultSchema}].vwRecordChanges rc 
    ON 
    ({{ PrimaryKeyJoin }} = rc.RecordID) AND 
    rc.Type = ''Create'' AND 
    rc.EntityID = {{ EntityID | sqlString }} 
WHERE 
    rc.RecordID IS NULL;
'
