SET
  @ID_85a3d045 = '46a91235-2122-40e8-9289-20d04489cac5'
SET
  @Name_85a3d045 = N'ExternalChangeDetection_DetectUpdates'
SET
  @CategoryID_85a3d045 = 'FE1AE5B2-FC57-43B2-B560-A673713E1679'
SET
  @Description_85a3d045 = N'Detects updated records in an external system by comparing UpdatedAt timestamps.'
SET
  @SQL_85a3d045 = N'-- T-SQL variant for External Change Detection - Detect Updates
SELECT 
    {{ ColumnList }}, ot.[{{ UpdatedAtField }}] AS UpdatedAt, rc.last_change_time LatestRecordChangeAt
FROM 
    [{{ SchemaName }}].[{{ BaseView }}] ot
INNER JOIN (
    SELECT 
        RecordID, MAX(ChangedAt) AS last_change_time
    FROM 
        [${flyway:defaultSchema}].vwRecordChanges
    WHERE 
        Type IN (''Update'', ''Create'') AND EntityID = {{ EntityID | sqlString }}
    GROUP BY 
        RecordID
) rc ON {{ PrimaryKeyJoin }} = rc.RecordID
WHERE 
    ot.[{{ UpdatedAtField }}] > COALESCE(rc.last_change_time, ''1900-01-01 00:00:00.000'');
'
