SET
  @ID_93f61311 = '028a39f6-2b38-4ed1-8235-4671b7cd330b'
SET
  @Name_93f61311 = N'ExternalChangeDetection_DetectDeletions'
SET
  @CategoryID_93f61311 = 'FE1AE5B2-FC57-43B2-B560-A673713E1679'
SET
  @Description_93f61311 = N'Detects deleted records in an external system by identifying MJ record changes with no matching rows in the base view.'
SET
  @SQL_93f61311 = N'-- T-SQL variant for External Change Detection - Detect Deletions
-- TECHNICAL DEBT: Joining on dynamically generated PrimaryKeyJoin (a concatenated string) prevents
-- the use of indexes on the organic table (ot). For massive tables, this will result in a table scan.
-- A future schema change to separate RecordID parts into native columns is recommended.
SELECT 
    rc.RecordID, MAX(rc.ChangedAt) ChangedAt
FROM 
    [${flyway:defaultSchema}].vwRecordChanges rc
LEFT JOIN 
    [{{ SchemaName }}].[{{ BaseView }}] ot 
    ON 
    rc.RecordID = {{ PrimaryKeyJoin }}
WHERE 
    {{ PrimaryKeyIsNull }}
    AND 
        rc.EntityID = {{ EntityID | sqlString }} 
    AND 
        rc.Type <> ''Delete''
GROUP BY 
    rc.RecordID
HAVING 
    MAX(CASE WHEN rc.Type = ''Delete'' THEN 1 ELSE 0
END) = 0;
'
