DECLARE @ID_682c16a7 UNIQUEIDENTIFIER,
@QueryID_682c16a7 UNIQUEIDENTIFIER,
@SQLDialectID_682c16a7 UNIQUEIDENTIFIER,
@SQL_682c16a7 NVARCHAR(MAX)
SET
  @ID_682c16a7 = 'd85de0ad-5b5b-4ef4-82bc-c634ce39e836'
SET
  @QueryID_682c16a7 = '3366D42B-C3A1-4CE0-9F40-7FBE15F2EA57'
SET
  @SQLDialectID_682c16a7 = '426915F2-D4FE-4AB9-97A8-39063561DE9F'
SET
  @SQL_682c16a7 = N'-- PostgreSQL variant for External Change Detection - Detect Creations
SELECT 
    {{ ColumnList }}, ot."{{ CreatedAtField }}" AS "CreatedAt", ot."{{ UpdatedAtField }}" AS "UpdatedAt"
FROM 
    "{{ SchemaName }}"."{{ BaseView }}" ot
LEFT JOIN 
    [${flyway:defaultSchema}].vwRecordChanges rc 
    ON 
    ({{ PrimaryKeyJoin }} = rc.RecordID) AND 
    rc.Type = ''Create'' AND 
    rc.EntityID = {{ EntityID | sqlString }} 
WHERE 
    rc.RecordID IS NULL;
'
EXEC [${flyway:defaultSchema}].spCreateQuerySQL @ID = @ID_682c16a7,
  @QueryID = @QueryID_682c16a7,
  @SQLDialectID = @SQLDialectID_682c16a7,
  @SQL = @SQL_682c16a7;

-- Save MJ: Query SQLs (core SP call only)
DECLARE @ID_8a979854 UNIQUEIDENTIFIER,
@QueryID_8a979854 UNIQUEIDENTIFIER,
@SQLDialectID_8a979854 UNIQUEIDENTIFIER,
@SQL_8a979854 NVARCHAR(MAX)
SET
  @ID_8a979854 = '565c5af3-5f59-4531-b21d-53ebc884ef5b'
SET
  @QueryID_8a979854 = '46A91235-2122-40E8-9289-20D04489CAC5'
SET
  @SQLDialectID_8a979854 = '426915F2-D4FE-4AB9-97A8-39063561DE9F'
SET
  @SQL_8a979854 = N'-- PostgreSQL variant for External Change Detection - Detect Updates
SELECT 
    {{ ColumnList }}, ot."{{ UpdatedAtField }}" AS "UpdatedAt", rc.last_change_time AS "LatestRecordChangeAt"
FROM 
    "{{ SchemaName }}"."{{ BaseView }}" ot
INNER JOIN (
    SELECT 
        RecordID, MAX(ChangedAt) AS last_change_time
    FROM 
        [${flyway:defaultSchema}].vwRecordChanges
    WHERE 
        Type IN (''Update'', ''Create'') AND EntityID = {{ EntityID | sqlString }}
    GROUP BY 
        RecordID
) rc ON {{ PrimaryKeyJoin }} = rc.RecordID
WHERE 
    ot."{{ UpdatedAtField }}" > COALESCE(rc.last_change_time, CAST(''1900-01-01 00:00:00.000'' AS TIMESTAMPTZ));
'
EXEC [${flyway:defaultSchema}].spCreateQuerySQL @ID = @ID_8a979854,
  @QueryID = @QueryID_8a979854,
  @SQLDialectID = @SQLDialectID_8a979854,
  @SQL = @SQL_8a979854;

