DECLARE @ID_062985da UNIQUEIDENTIFIER,
@QueryID_062985da UNIQUEIDENTIFIER,
@SQLDialectID_062985da UNIQUEIDENTIFIER,
@SQL_062985da NVARCHAR(MAX)
SET
  @ID_062985da = 'f325dcbe-347f-4f59-9a8a-a18706803c8b'
SET
  @QueryID_062985da = '028A39F6-2B38-4ED1-8235-4671B7CD330B'
SET
  @SQLDialectID_062985da = '426915F2-D4FE-4AB9-97A8-39063561DE9F'
SET
  @SQL_062985da = N'-- PostgreSQL variant for External Change Detection - Detect Deletions
-- TECHNICAL DEBT: Joining on dynamically generated PrimaryKeyJoin (a concatenated string) prevents
-- the use of indexes on the organic table (ot). For massive tables, this will result in a table scan.
-- A future schema change to separate RecordID parts into native columns is recommended.
SELECT 
    rc.RecordID, MAX(rc.ChangedAt) AS "ChangedAt"
FROM 
    [${flyway:defaultSchema}].vwRecordChanges rc
LEFT JOIN 
    "{{ SchemaName }}"."{{ BaseView }}" ot 
    ON 
    rc.RecordID = {{ PrimaryKeyJoin }}
WHERE 
    {{ PrimaryKeyIsNull }}
    AND 
        rc.EntityID = {{ EntityID | sqlString }} 
    AND 
        rc.Type <> ''Delete''
GROUP BY 
    rc.RecordID
HAVING 
    MAX(CASE WHEN rc.Type = ''Delete'' THEN 1 ELSE 0
END) = 0;
'
EXEC [${flyway:defaultSchema}].spCreateQuerySQL @ID = @ID_062985da,
  @QueryID = @QueryID_062985da,
  @SQLDialectID = @SQLDialectID_062985da,
  @SQL = @SQL_062985da;


